from dataclasses import dataclass, field
from datetime import datetime

@dataclass
class InferenceFootprintTracker:
    service_name: str
    region: str
    gpu_model: str
    gpu_count: int
    gpu_tdp_kw: float
    pue: float = 1.2
    cfe_fraction: float = 0.0

    # Running totals
    total_requests: int   = 0
    total_tokens_out: int = 0
    total_hours_run: float = 0.0

    def carbon_intensity(self) -> float:
        grid = CARBON_INTENSITY.get(self.region, 0.35)
        return grid * (1.0 - self.cfe_fraction)

    def record_window(self, hours: float, requests: int, tokens_out: int) -> None:
        self.total_hours_run  += hours
        self.total_requests   += requests
        self.total_tokens_out += tokens_out

    def total_kwh(self) -> float:
        return self.gpu_count * self.gpu_tdp_kw * self.total_hours_run * self.pue

    def total_co2e_kg(self) -> float:
        return self.total_kwh() * self.carbon_intensity()

    def co2e_per_1k_requests(self) -> float:
        if self.total_requests == 0:
            return 0.0
        return (self.total_co2e_kg() / self.total_requests) * 1000.0

    def co2e_per_1m_tokens(self) -> float:
        if self.total_tokens_out == 0:
            return 0.0
        return (self.total_co2e_kg() / self.total_tokens_out) * 1_000_000.0

    def summary(self) -> str:
        return (
            f"{self.service_name}: {self.total_co2e_kg():.2f} kg CO₂e total | "
            f"{self.co2e_per_1k_requests():.4f} kg/1k req | "
            f"{self.co2e_per_1m_tokens():.4f} kg/1M tokens"
        )

from dataclasses import dataclass, field
from collections import defaultdict

@dataclass
class CarbonAllocationRecord:
    business_unit: str
    project_name: str
    cloud_account_id: str        # AWS account, GCP project, Azure subscription
    period_start: str            # ISO date
    period_end: str
    kwh_consumed: float
    co2e_kg: float
    cost_usd: float              # Paired with financial chargeback
    data_sources: list[str] = field(default_factory=list)  # e.g. ["aws-carbon-tool", "codecarbon"]

class CarbonLedger:
    def __init__(self) -> None:
        self._records: list[CarbonAllocationRecord] = []

    def add(self, record: CarbonAllocationRecord) -> None:
        self._records.append(record)

    def by_business_unit(self) -> dict[str, float]:
        totals: dict[str, float] = defaultdict(float)
        for r in self._records:
            totals[r.business_unit] += r.co2e_kg
        return dict(totals)

    def total_tco2e(self) -> float:
        return sum(r.co2e_kg for r in self._records) / 1000.0

    def top_emitters(self, n: int = 5) -> list[tuple[str, float]]:
        by_project: dict[str, float] = defaultdict(float)
        for r in self._records:
            by_project[r.project_name] += r.co2e_kg
        return sorted(by_project.items(), key=lambda x: -x[1])[:n]
